//! # Machine
//!
//! This module represents a **3-Axis Computer Numerical Control** (CNC) machine.
//!
//! The machine runs on parsed [`Code`],
//! generated by the **G-Code [`Parser`](crate::parser::parser)** module.

use crate::parser::{Float, Int, parser::*};
use std::{
    fmt::{Debug, Display},
    ops::Neg,
};

/// Starting point of a machine with all axes at '0'.
pub const HOME_POS: Point = Point::new(0.0, 0.0, 0.0);

/// Maximum and Minimum values supported for [`Machine::max_travels`] for this module.
/// The fields of these [`Point`]s will be treated in [`Unit::default`] system.
const MAX_TRAVELS: Point = Point::new(1500.0, 1000.0, 1000.0);
const MIN_TRAVELS: Point = Point::new(150.0, 100.0, 100.0);

/// Ratio to maintain between axes lengths.
/// The order of specific axes is as follows:
/// - X : Y
/// - X : Z
/// - Y : Z
const MAX_RATIO: Point = Point::new(2.0, 2.0, 1.5);
const MIN_RATIO: Point = Point::new(1.0, 1.0, 0.5);

/// Possible unit standards for measurable values.
#[derive(Copy, Clone, Default, Debug, PartialEq)]
pub enum Unit {
    Imperial,
    #[default]
    Metric,
}

/// Possible planes for a 3-axis machine.
#[derive(Copy, Clone, Default, Debug, PartialEq)]
pub enum Plane {
    #[default]
    XY,
    XZ,
    YZ,
}

/// Possible ways to interpret axis commands.
#[derive(Default, Debug)]
pub enum Positioning {
    #[default]
    Absolute,
    Incremental,
}

/// Possible ways to turn spindle on.
#[derive(Default, Debug)]
pub enum CircularDirection {
    #[default]
    Clockwise,
    CounterClockwise,
}

/// Represents the current state of a [`Machine`](crate::machine).
#[derive(Debug)]
pub struct Machine {
    /// Interpret state values in the selected `units`.
    /// The Code the machine executes MAY OR MAY NOT be in the same units.
    /// All stored values must be in this unit standard.
    units: Unit,

    /// Interpret [`Code`]s in the selected `code_units`.
    code_units: Unit,

    /// **Positive extreme values** for each linear axis.
    /// The other extreme would naturally be `HOME_POS`.
    /// The values in this struct will be assumed to be in [`units`](Self::units).
    max_travels: Point,

    /// Workpiece offset, used to change relative zero point with `G54`.
    work_offset: Point,

    /// Current position of each axis.
    pos: Point,

    /// Current tool in the spindle.
    tool: Int,

    /// Optionally preload next tool, to be changed on *tool change (`M6`)* command.
    next_tool: Option<Int>,

    /// Commanded RPM for the spindle.
    speed: Option<Int>,
    spindle_on: bool,
    spindle_dir: CircularDirection,

    /// Commanded cutting feed rate.
    feed: Option<Float>,

    coolant: bool,

    /// Plane to execute the [`Code`] on.
    plane: Plane,

    /// Interpret axis values absolutly or relatively.
    positioning: Positioning,

    /// Selected offset for tool diameter with a `D` code.
    dia_offset: Option<Int>,

    /// Selected offset for tool height with a `H` code.
    height_offset: Option<Int>,
}

impl Machine {
    /// Constructs a new instance of [`Machine`] with all axes at [`HOME_POS`].
    ///
    /// Accepts a [`Point`], indicating positive extremes of the Machine to construct,
    /// and the measuring system [`Unit`] to use for machine moves.
    ///
    /// The *G-Code* that the machine executes need not be in the same [`Unit`]s.
    ///
    /// Returns a new `Machine` instance on success or [`MachineError`] on failure.
    ///
    /// # Errors:
    /// - [`MachineError::NegativeTravels`] --
    /// At least one axis is detected to have a negative value.
    /// - [`MachineError::TravelsTooLong`] --
    /// At least one axis is longer than what the constructor supports.
    /// - [`MachineError::TravelsTooShort`] --
    /// At least one axis is shorter than what the constructor supports.
    /// - [`MachineError::WrongRatio`] --
    /// At least two axes have weird values.
    pub fn build(max_travels: Point, units: Unit) -> Result<Self, MachineError> {
        let ratio = max_travels.ratio();

        if max_travels.any_negative() {
            Err(MachineError::NegativeTravels)
        } else if max_travels.over(&MAX_TRAVELS) {
            Err(MachineError::TravelsTooLong)
        } else if max_travels.under(&MIN_TRAVELS) {
            Err(MachineError::TravelsTooShort)
        } else if ratio.over(&MAX_RATIO) || ratio.under(&MIN_RATIO) {
            Err(MachineError::WrongRatio)
        } else {
            Ok(Machine {
                units,
                code_units: units,
                max_travels,
                work_offset: Point::default(),
                pos: Point::default(),
                tool: 0,
                next_tool: None,
                speed: None,
                spindle_on: false,
                spindle_dir: CircularDirection::default(),
                feed: None,
                coolant: false,
                plane: Plane::default(),
                positioning: Positioning::default(),
                dia_offset: None,
                height_offset: None,
            })
        }
    }

    //
    // ########## PUBLIC GETTERS ##########
    //

    /// Return *maximum* travel for each axis of the [`Machine`].
    pub fn max_travels(&self) -> &Point {
        &self.max_travels
    }

    /// Returns `G54` work coordinate system.
    ///
    /// This offset is applied each time the machine has to move in absolute mode.
    pub fn work_offset(&self) -> &Point {
        &self.work_offset
    }

    /// Returns the current position of the machine.
    pub fn pos(&self) -> &Point {
        &self.pos
    }

    //
    // ########## PUBLIC SETTERS ##########
    //

    /// Interpret [`Code`] values in a new [`Unit`] standard.
    pub fn set_code_units(&mut self, code_units: Unit) {
        self.code_units = code_units;
    }

    /// Set `G54` work coordinate system.
    ///
    /// **This is not verified to be inside the machine travels**.
    pub fn set_work_offset(&mut self, work_offset: Point) {
        self.work_offset = work_offset;
    }

    /// Preload the *next tool* to use.
    pub fn set_next_tool(&mut self, next_tool: Int) {
        self.next_tool = Some(next_tool);
    }

    /// Set *spindle RPMs* to use.
    pub fn set_speed(&mut self, speed: Int) {
        self.speed = Some(speed);
    }

    /// Turn spindle off.
    pub fn spindle_off(&mut self) {
        self.spindle_on = false;
    }

    /// Set *feedrate* to use.
    /// Peformes any unit conversion if necessary.
    pub fn set_feed(&mut self, mut feed: Float) {
        if self.units == Unit::Imperial && self.code_units == Unit::Metric {
            feed /= 25.4;
        } else if self.units == Unit::Metric && self.code_units == Unit::Imperial {
            feed *= 25.4;
        }

        self.feed = Some(feed);
    }

    /// Set `coolant` on or off.
    pub fn set_coolant(&mut self, coolant: bool) {
        self.coolant = coolant;
    }

    /// Set active plane.
    pub fn set_plane(&mut self, plane: Plane) {
        self.plane = plane;
    }

    /// Toggle between absolute or relative positioning.
    pub fn set_positioning(&mut self, positioning: Positioning) {
        self.positioning = positioning;
    }

    //
    // ########## PUBLIC SETTERS, CAN FAIL ##########
    //

    /// Turn spindle on, if not already on.
    ///
    /// Accepts [`CircularDirection`] as *spindle direction* and optionally accepts
    /// new *spindle speed*, otherwise uses speed from previous blocks, if present.
    ///
    /// Returns [`MachineError::NoSpindleSpeed`] if no spindle speed was commanded before and
    /// `speed` provided is also `None`.
    pub fn spindle_on(
        &mut self,
        dir: CircularDirection,
        speed: Option<Int>,
    ) -> Result<(), MachineError> {
        self.speed = speed.or(self.speed);
        self.spindle_dir = dir;

        match self.speed {
            Some(_) => {
                self.spindle_on = true;
                Ok(())
            }
            None => Err(MachineError::NoSpindleSpeed),
        }
    }

    /// Changes current `tool` to:
    /// - `new_tool`, if the value is `Some`.
    /// - `next_tool`, if a tool was preloaded.
    ///
    /// `next_tool` will be always be set to `None` after the tool change.
    ///
    /// Returns [`MachineError::NoTool`] if no `next_tool` was commanded before and
    /// `new_tool` provided is also `None`.
    pub fn tool_change(&mut self, new_tool: Option<Int>) -> Result<(), MachineError> {
        self.next_tool = new_tool.or(self.next_tool);

        match self.next_tool {
            Some(t) => {
                self.tool = t;
                self.next_tool = None;
                Ok(())
            }
            None => Err(MachineError::NoTool),
        }
    }

    //
    // ########## PUBLIC INTERPOLATION METHODS ##########
    //

    /// Moves machine after checking for [`Positioning`] setting of the machine in **Rapid** rate.
    ///
    /// Respects the current unit selections for both [`Machine`] and [`Code`],
    /// and any unit conversions are performed as necessary.
    ///
    /// Returns [`MachineError`] on failure.
    ///
    /// # Errors:
    /// - [`MachineError::Overtravel`] -- Atleast one axis exceeds `max_travels` or `HOME_POS`.
    pub fn rapid_move(&mut self, pos: PartialPoint) -> Result<(), MachineError> {
        self.move_machine(pos)
    }

    /// Moves machine after checking for [`Positioning`] setting of the machine in **Feed** rate.
    ///
    /// Respects the current unit selections for both [`Machine`] and [`Code`],
    /// and any unit conversions (including for **feedrate**) are performed as necessary.
    ///
    /// Returns [`MachineError`] on failure.
    ///
    /// # Errors:
    /// - [`MachineError::Overtravel`] -- Atleast one axis exceeds `max_travels` or `HOME_POS`.
    /// - [`MachineError::NoFeed`] -- No feed was commanded in previous blocks and is found `None`.
    pub fn feed_move(
        &mut self,
        pos: PartialPoint,
        feed: Option<Float>,
    ) -> Result<(), MachineError> {
        if let Some(f) = feed {
            self.set_feed(f); // takes care of any unit conversion
        }

        match self.feed {
            Some(_) => {
                // move only when feed is detected.
                Ok(self.move_machine(pos)?)
            }
            None => Err(MachineError::NoFeed),
        }
    }

    pub fn circular_move(
        &mut self,
        mut pos: PartialPoint,
        method: CircleMethod,
        dir: CircularDirection,
        feed: Option<Float>,
    ) -> Result<(PlanarPoint, Float), MachineError> {
        if let Some(f) = feed {
            self.set_feed(f);
        }

        if self.feed.is_none() {
            return Err(MachineError::NoFeed);
        }

        let start_pos = self.pos();
        let mut end_pos = start_pos.clone();
        // retain None variants as start_pos
        self.to_machine_units_partial(&mut pos); // pos will now be in same units as start_pos
        end_pos.set_optional(pos.x(), pos.y(), pos.z());

        let (start_pos_planar, end_pos_planar) = match self.plane {
            Plane::XY => (
                PlanarPoint::new(self.plane, start_pos.x(), start_pos.y()),
                PlanarPoint::new(self.plane, end_pos.x(), end_pos.y()),
            ),
            Plane::XZ => (
                PlanarPoint::new(self.plane, start_pos.x(), start_pos.z()),
                PlanarPoint::new(self.plane, end_pos.x(), end_pos.z()),
            ),
            Plane::YZ => (
                PlanarPoint::new(self.plane, start_pos.y(), start_pos.z()),
                PlanarPoint::new(self.plane, end_pos.y(), end_pos.z()),
            ),
        };

        // convert `method` units
        let method = match method {
            CircleMethod::RelativePoint(mut rel_center) => {
                self.to_machine_units_partial(&mut rel_center);
                CircleMethod::RelativePoint(rel_center)
            }
            CircleMethod::FixedRadius(mut rad) => {
                if self.units == Unit::Imperial && self.code_units == Unit::Metric {
                    rad /= 25.4;
                } else if self.units == Unit::Metric && self.code_units == Unit::Imperial {
                    rad *= 25.4;
                };

                CircleMethod::FixedRadius(rad)
            }
        };

        let (center, radius) = circle_info(&start_pos_planar, &end_pos_planar, method, dir)?;

        // check if the midpoint of the arc will be in the machine limits

        // now we know the circle is possible
        // and end_pos is already in machine units
        self.set_pos_no_conversion(end_pos)?;

        Ok((center, radius))
    }

    /// Moves `Some` variants of `pos` to the value inside.
    ///
    /// This function differs from [`move_machine`](Self::move_machine) in the way that,
    /// it does not consider any `work_offset` & `positioning` setting of the [`Machine`] and just
    /// moves the machine axes to desired location.
    ///
    /// Returns [`MachineError::Overtravel`] if any axis exceeds `max_travels` or `HOME_POS`,
    /// indicating failure.
    ///
    /// This function also respects the current unit selections for both [`Machine`] and [`Code`],
    /// and any unit conversions are performed as necessary.
    pub fn move_machine_pos(&mut self, pos: PartialPoint) -> Result<(), MachineError> {
        let new_pos = Point::new(
            pos.x().unwrap_or(self.pos().x()),
            pos.y().unwrap_or(self.pos().y()),
            pos.z().unwrap_or(self.pos().z()),
        );

        self.set_pos(new_pos)
    }

    //
    // ########## INTERPOLATION HELPER METHODS ##########
    //

    /// Moves the machine axes to absolute coordinates present in `pos`.
    /// Applies `work_offset`, if present, before making the move.
    fn move_absolute(&mut self, pos: PartialPoint) -> Result<(), MachineError> {
        let new_pos = Point::new(
            pos.x()
                .map_or(self.pos().x(), |x| self.work_offset().x() + x),
            pos.y()
                .map_or(self.pos().y(), |y| self.work_offset().y() + y),
            pos.z()
                .map_or(self.pos().z(), |z| self.work_offset().z() + z),
        );

        self.set_pos(new_pos)
    }

    /// Moves the machine axes relatively from current position.
    /// `work_offset` has no effect on behaviour of this function.
    fn move_incremental(&mut self, delta: PartialPoint) -> Result<(), MachineError> {
        let new_pos = Point::new(
            self.pos().x() + delta.x().unwrap_or(0.0),
            self.pos().y() + delta.y().unwrap_or(0.0),
            self.pos().z() + delta.z().unwrap_or(0.0),
        );

        self.set_pos(new_pos)
    }

    /// Moves machine after checking for [`Positioning`] setting of the machine.
    ///
    /// Returns [`MachineError::Overtravel`] if any axis exceeds `max_travels` or `HOME_POS`,
    /// indicating failure.
    ///
    /// Respects the current unit selections for both [`Machine`] and [`Code`],
    /// and any unit conversions are performed as necessary.
    pub fn move_machine(&mut self, pos: PartialPoint) -> Result<(), MachineError> {
        match self.positioning {
            Positioning::Absolute => self.move_absolute(pos),
            Positioning::Incremental => self.move_incremental(pos),
        }
    }

    /// Set the current machine position for all axes.
    /// Respects the current unit selections for both [`Machine`] and [`Code`].
    ///
    /// Returns [`MachineError::Overtravel`] if any axis exceeds `max_travels` or `HOME_POS`,
    /// indicating failure.
    fn set_pos(&mut self, mut pos: Point) -> Result<(), MachineError> {
        self.to_machine_units(&mut pos);
        self.set_pos_no_conversion(pos)
    }

    /// Set the current machine position for all axes.
    /// Does **NO UNIT CONVERSION**, even if the *machine* and *code* units differ.
    ///
    /// Returns [`MachineError::Overtravel`] if any axis exceeds `max_travels` or `HOME_POS`,
    /// indicating failure.
    fn set_pos_no_conversion(&mut self, pos: Point) -> Result<(), MachineError> {
        if pos.over(&self.max_travels) || pos.under(&HOME_POS) {
            Err(MachineError::Overtravel)
        } else {
            self.pos = pos;
            Ok(())
        }
    }

    //
    // ########## OTHER HELPER METHODS ##########
    //

    /// Accepts a *mutable reference to [`Point`]* in `code_units`.
    /// Converts the units of all fields to Machine units.
    fn to_machine_units(&self, point: &mut Point) {
        if self.units == Unit::Imperial && self.code_units == Unit::Metric {
            point.to_imperial()
        } else if self.units == Unit::Metric && self.code_units == Unit::Imperial {
            point.to_metric()
        }
    }

    /// Accepts a *mutable reference to [`Point`]* in `code_units`.
    /// Converts the units of all `Some` variant fields to Machine units.
    /// `None` variants are not changed.
    fn to_machine_units_partial(&self, point: &mut PartialPoint) {
        if self.units == Unit::Imperial && self.code_units == Unit::Metric {
            point.to_imperial()
        } else if self.units == Unit::Metric && self.code_units == Unit::Imperial {
            point.to_metric()
        }
    }
}

/// A *tuple struct* that represents a **2D Point** on a specific **Plane**.
#[derive(Debug, PartialEq)]
pub struct PlanarPoint(Plane, Float, Float);

impl PlanarPoint {
    /// Constructor for a [`PlanarPoint`].
    ///
    /// For a given [`Plane`], *first* represents the value for first axis letter and *second*
    /// represents the second axis letter.
    /// For example:
    /// ```
    /// PlanarPoint::new(Plane::XY, 1.0, 2.0); // Constructs point with X = 1.0 & Y = 2.0.
    /// PlanarPoint::new(Plane::XZ, 3.0, 4.0); // Constructs point with X = 3.0 & Z = 4.0.
    /// PlanarPoint::new(Plane::YZ, 5.0, 6.0); // Constructs point with Y = 5.0 & Z = 6.0.
    /// ```
    pub fn new(plane: Plane, first: Float, second: Float) -> Self {
        Self(plane, first, second)
    }

    /// Returns selected plane for the point.
    pub fn plane(&self) -> Plane {
        self.0
    }

    /// Returns the first axis value for the selected plane.
    pub fn first(&self) -> Float {
        self.1
    }

    /// Returns the second axis value for the selected plane.
    pub fn second(&self) -> Float {
        self.2
    }

    /// Calculates distance between two [`PlanarPoint`]s.
    ///
    /// Both the points must lie on the **same plane**, otherwise [`MachineError::PointsOffPlane`]
    /// is returned.
    pub fn dist(&self, other: &Self) -> Result<Float, MachineError> {
        if self.plane() == other.plane() {
            Ok(
                ((self.first() - other.first()).powi(2) + (self.second() - other.second()).powi(2))
                    .sqrt(),
            )
        } else {
            Err(MachineError::PointsOffPlane)
        }
    }
}

/// Validate if an *arc* is possible between two points and return its properties.
/// This function takes care of all the geometric Math for circular interpolation paths.
///
/// Accepts:
/// - Start and end points of the arc as [`PlanarPoint`]s, which must lie on the same plane.
/// - [`CircleMethod`] to use for calculating the radius of possible arc(s).
/// - [`CircularDirection`] for selecting a particular center point, in case more than one circles
/// are possible.
///
/// On success, returns a *tuple* consisting of two fields:
/// - The *center [`PlanarPoint`]* of the circle that satisfies the given conditions.
/// - The *radius* of the said circle.
///
/// On failure, returns [`MachineError`].
///
/// # Reference: [`Math Stack Exchange`](https://math.stackexchange.com/questions/1781438/finding-the-center-of-a-circle-given-two-points-and-a-radius-algebraically)
///
/// # Errors:
/// - [`MachineError::PointsOffPlane`] -- Both points do not lie on the requested plane.
/// - [`MachineError::PointsIntersect`] -- Both provided points have the same coordinates.
/// - [`MachineError::CenterOffPlane`] -- The relative center provided does not lie on the
/// requested plane.
/// - [`MachineError::InvalidCircle`] -- The provided or calculated radius does not satisfy both
/// the points.
fn circle_info(
    current_pos: &PlanarPoint,
    new_pos: &PlanarPoint,
    method: CircleMethod,
    dir: CircularDirection,
) -> Result<(PlanarPoint, Float), MachineError> {
    // plane to create the circle on
    let plane = current_pos.plane();

    if new_pos.plane() != plane {
        return Err(MachineError::PointsOffPlane);
    }

    if current_pos == new_pos {
        return Err(MachineError::PointsIntersect);
    }

    match method {
        CircleMethod::RelativePoint(ref rel_center) => {
            // all fields cannot be None or Some.
            if rel_center.is_none() || rel_center.is_some() {
                panic!("Inalid Relative Center passed parser. Logic Error!");
            }

            // absolute center on the same plane as both the points
            let center = match plane {
                Plane::XY if rel_center.z().is_some() => return Err(MachineError::CenterOffPlane),

                Plane::XZ if rel_center.y().is_some() => return Err(MachineError::CenterOffPlane),

                Plane::YZ if rel_center.x().is_some() => return Err(MachineError::CenterOffPlane),

                Plane::XY => PlanarPoint::new(
                    plane,
                    rel_center
                        .x()
                        .map_or(current_pos.first(), |x| current_pos.first() + x),
                    rel_center
                        .y()
                        .map_or(current_pos.second(), |y| current_pos.second() + y),
                ),

                Plane::XZ => PlanarPoint::new(
                    plane,
                    rel_center
                        .x()
                        .map_or(current_pos.first(), |x| current_pos.first() + x),
                    rel_center
                        .z()
                        .map_or(current_pos.second(), |z| current_pos.second() + z),
                ),

                Plane::YZ => PlanarPoint::new(
                    plane,
                    rel_center
                        .y()
                        .map_or(current_pos.first(), |y| current_pos.first() + y),
                    rel_center
                        .z()
                        .map_or(current_pos.second(), |z| current_pos.second() + z),
                ),
            };

            let radius = current_pos.dist(&center)?;

            // in this method the distance between the points cannot be greater than the diameter

            // new point not at the same distance.
            if (new_pos.dist(&center)? - radius).abs() > 1e-10 {
                Err(MachineError::InvalidCircle(method))
            } else {
                Ok((center, radius))
            }
        }

        CircleMethod::FixedRadius(radius) => {
            assert!(
                radius.abs() > 1e-10,
                "Invalid radius passed parser. Logic Error!."
            );

            // if radius is negative, make it positive and make the function choose the major arc
            // otherwise choose minor arc on positive R value
            let (radius, minor) = if radius.signum() == 1.0 {
                (radius, true)
            } else if radius.signum() == -1.0 {
                (radius.neg(), false)
            } else {
                panic!("Provided number is Not a Number (NaN).");
            };

            let dist = current_pos.dist(&new_pos)?;

            // distance more than diameter
            if dist > 2.0 * radius.abs() {
                return Err(MachineError::InvalidCircle(method));
            }

            let midpoint = PlanarPoint::new(
                plane,
                current_pos.first().midpoint(new_pos.first()),
                current_pos.second().midpoint(new_pos.second()),
            );

            // how much is the midpoint off from the current position.
            // plane is irrelevant in this var.
            let delta = PlanarPoint::new(
                plane,
                midpoint.first() - current_pos.first(),
                midpoint.second() - current_pos.second(),
            );

            // points are on the diameter
            if (2.0 * radius - dist).abs() < 1e-10 {
                return Ok((midpoint, radius));
            }

            // make dist as distance to midpoint only
            let dist = dist / 2.0;

            // length of line joining midpoint and center, the perpendicular bisector
            let bisector = (radius.powi(2) - dist.powi(2)).sqrt();

            // TODO create diagram to prove the result for all 4 quadrants
            let center = match (minor, dir) {
                (true, CircularDirection::Clockwise)
                | (false, CircularDirection::CounterClockwise) => PlanarPoint::new(
                    plane,
                    midpoint.first() + (bisector * delta.second()) / dist,
                    midpoint.second() - (bisector * delta.first()) / dist,
                ),

                (true, CircularDirection::CounterClockwise)
                | (false, CircularDirection::Clockwise) => PlanarPoint::new(
                    plane,
                    midpoint.first() - (bisector * delta.second()) / dist,
                    midpoint.second() + (bisector * delta.first()) / dist,
                ),
            };

            Ok((center, radius))
        }
    }
}

/// Possible errors that can happen during machine construction.
#[derive(Debug, PartialEq)]
pub enum MachineError {
    /// Negative value(s) detected during machine construction.
    NegativeTravels,
    TravelsTooLong,
    TravelsTooShort,
    /// The resulting machine would be an odd shape.
    WrongRatio,
    Overtravel,
    /// Spindle On was commanded, but no spindle speed was provided.
    NoSpindleSpeed,
    /// Tool change was commanded, but no tool number was provided.
    NoTool,
    /// Feed move was commanded, but no feed was provided.
    NoFeed,
    /// Points of the requested circle do not lie on the same plane.
    PointsOffPlane,
    /// Both provided circle points are the same.
    PointsIntersect,
    /// Circle not possible due to method specific method requirements.
    InvalidCircle(CircleMethod),
    /// Provided center point does not lie on the selected plane.
    CenterOffPlane,
}

impl Display for MachineError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> Result<(), std::fmt::Error> {
        write!(
            f,
            "{}",
            match self {
                Self::NegativeTravels => format!(
                    "Machine travels cannot be negative.\nPlease provide a valid positive value between: {MAX_TRAVELS:?} and {MIN_TRAVELS:?}"
                ),
                Self::TravelsTooLong => format!(
                    "Cannot construct a 'Machine' this long.\nPlease provide values less than: {MAX_TRAVELS:?}"
                ),
                Self::TravelsTooShort => format!(
                    "Cannot construct a 'Machine' this short.\nPlease provide values larger than: {MIN_TRAVELS:?}"
                ),
                Self::WrongRatio => format!(
                    "The resultant machine would have a particular axis too long or too short.\nPlease reconsider axis lengths."
                ),
                Self::Overtravel => format!(
                    "Overtravel:\nAt least one axis of the machine overtravels because of the last move."
                ),
                Self::NoSpindleSpeed => format!(
                    "No Spindle Speed Commanded:\nA spindle action was commanded, but no 'S' was detected throughout the program."
                ),
                Self::NoTool => format!(
                    "No Tool Commanded:\nA tool change was commanded, but no 'T' was detected on the same block and no tool was preloaded."
                ),
                Self::NoFeed => format!(
                    "No Feed Commanded:\nA feed move was commanded, but no 'F' was detected throughout the program."
                ),
                Self::PointsOffPlane => format!(
                    "Points are not detected to be on the same plane:\nBoth the points must be on the same plane to be considered valid."
                ),
                Self::PointsIntersect => format!(
                    "Ambiguous Circle Detected:\nThe start and end points of the requested circle are same and therefore the circle cannot be constructed. "
                ),
                Self::InvalidCircle(method) => match method {
                    CircleMethod::RelativePoint(_) => format!(
                        "Invalid Circle Requested:\nThe start and end points of the requested circle are not found to be at the same distance from the specified center, which is invalid."
                    ),
                    CircleMethod::FixedRadius(_) => format!(
                        "Invalid Circle Requested:\nThe distance between the start and end points is found to be more than the diameter provided, which is invalid."
                    ),
                },
                Self::CenterOffPlane => format!(
                    "Invalid Relative Center Point Detected:\nThe relative center provided does not lie only on the selected plane, which is invalid."
                ),
            }
        )
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn construct_neg_travels() {
        assert_eq!(
            Machine::build(Point::new(150.0, -500.0, 500.0), Unit::default()).unwrap_err(),
            MachineError::NegativeTravels
        );
    }

    #[test]
    fn construct_long_travels() {
        assert_eq!(
            Machine::build(Point::new(2000.0, 1000.0, 500.0), Unit::default()).unwrap_err(),
            MachineError::TravelsTooLong
        );
    }

    #[test]
    fn construct_short_travels() {
        assert_eq!(
            Machine::build(Point::new(100.0, 75.0, 75.0), Unit::default()).unwrap_err(),
            MachineError::TravelsTooShort
        );
    }

    #[test]
    fn construct_wrong_ratio() {
        assert_eq!(
            Machine::build(Point::new(1500.0, 100.0, 100.0), Unit::default()).unwrap_err(),
            MachineError::WrongRatio
        );
    }

    #[test]
    // Must pass
    fn construct_good() {
        assert!(Machine::build(Point::new(1000.0, 750.0, 500.0), Unit::default()).is_ok());
    }

    // Test Machine methods

    #[test]
    fn overtravel_set() {
        let mut m = Machine::build(Point::new(1000.0, 750.0, 500.0), Unit::default()).unwrap();

        assert_eq!(
            m.set_pos(Point::new(-100.0, 500.0, 300.0)).unwrap_err(),
            MachineError::Overtravel
        );

        assert_eq!(
            m.set_pos(Point::new(1200.0, 500.0, 300.0)).unwrap_err(),
            MachineError::Overtravel
        );
    }

    #[test]
    fn unit_standards() {
        // machine metric and code metric
        let mut m = Machine::build(Point::new(1000.0, 750.0, 500.0), Unit::Metric).unwrap();
        m.set_code_units(Unit::Metric);
        m.move_machine(PartialPoint::new(Some(25.4), Some(25.4), Some(25.4)))
            .unwrap();
        assert_eq!(m.pos(), &Point::new(25.4, 25.4, 25.4));

        // machine imperial and code imperial
        let mut m = Machine::build(Point::new(1000.0, 750.0, 500.0), Unit::Imperial).unwrap();
        m.set_code_units(Unit::Imperial);
        m.move_machine(PartialPoint::new(Some(1.0), Some(1.0), Some(1.0)))
            .unwrap();
        assert_eq!(m.pos(), &Point::new(1.0, 1.0, 1.0));

        // machine imperial and code metric
        let mut m = Machine::build(Point::new(1000.0, 750.0, 500.0), Unit::Imperial).unwrap();
        m.set_code_units(Unit::Metric);
        m.move_machine(PartialPoint::new(Some(25.4), Some(25.4), Some(25.4)))
            .unwrap();
        assert_eq!(m.pos(), &Point::new(1.0, 1.0, 1.0));

        // machine metric and code imperial
        let mut m = Machine::build(Point::new(1000.0, 750.0, 500.0), Unit::Metric).unwrap();
        m.set_code_units(Unit::Imperial);
        m.move_machine(PartialPoint::new(Some(1.0), Some(1.0), Some(1.0)))
            .unwrap();
        assert_eq!(m.pos(), &Point::new(25.4, 25.4, 25.4));
    }

    #[test]
    fn absolute_move() {
        let mut m = Machine::build(Point::new(1000.0, 750.0, 500.0), Unit::Metric).unwrap();

        // with no g54 offset
        m.move_absolute(PartialPoint::new(Some(100.0), None, None))
            .unwrap();
        assert_eq!(m.pos(), &Point::new(100.0, 0.0, 0.0));

        // with g54 offset
        m.set_work_offset(Point::new(100.0, 100.0, 100.0));
        m.move_absolute(PartialPoint::new(Some(100.0), Some(0.0), None))
            .unwrap();
        assert_eq!(m.pos(), &Point::new(200.0, 100.0, 0.0));

        // overtravel
        assert_eq!(
            m.move_absolute(PartialPoint::new(Some(901.0), Some(0.0), None))
                .unwrap_err(),
            MachineError::Overtravel
        ); // tries to move X to 1001.0
    }

    #[test]
    fn incremental_move() {
        let mut m = Machine::build(Point::new(1000.0, 750.0, 500.0), Unit::Imperial).unwrap();

        // with no g54 offset
        m.move_incremental(PartialPoint::new(Some(100.0), None, None))
            .unwrap();
        assert_eq!(m.pos(), &Point::new(100.0, 0.0, 0.0));

        // with g54 offset
        m.set_work_offset(Point::new(100.0, 100.0, 100.0)); // has no effect
        m.move_incremental(PartialPoint::new(Some(200.0), Some(0.0), None))
            .unwrap();
        assert_eq!(m.pos(), &Point::new(300.0, 0.0, 0.0));

        // overtravel
        assert_eq!(
            m.move_incremental(PartialPoint::new(Some(100.0), Some(751.0), None))
                .unwrap_err(),
            MachineError::Overtravel
        ); // tries to move Y to 751.0
    }

    #[test]
    fn machine_move() {
        let mut m = Machine::build(Point::new(1000.0, 750.0, 500.0), Unit::Imperial).unwrap();

        // with no g54 offset
        m.move_machine_pos(PartialPoint::new(Some(100.0), None, Some(500.0)))
            .unwrap();
        assert_eq!(m.pos(), &Point::new(100.0, 0.0, 500.0));

        // with g54 offset
        m.set_work_offset(Point::new(100.0, 100.0, 100.0));
        m.move_machine_pos(PartialPoint::new(Some(200.0), Some(100.0), None))
            .unwrap(); // Z will be saved from previous move
        assert_eq!(m.pos(), &Point::new(200.0, 100.0, 500.0));

        // overtravel
        assert_eq!(
            m.move_machine_pos(PartialPoint::new(Some(0.0), Some(0.0), Some(-1.0)))
                .unwrap_err(),
            MachineError::Overtravel
        ); // tries to move Z to -1.0
    }

    #[test]
    fn spindle() {
        let mut m = Machine::build(Point::new(1000.0, 750.0, 500.0), Unit::Imperial).unwrap();

        assert_eq!(
            m.spindle_on(CircularDirection::default(), None)
                .unwrap_err(),
            MachineError::NoSpindleSpeed
        );

        // no speed required when preset before
        m.set_speed(1000);
        assert!(m.spindle_on(CircularDirection::default(), None).is_ok());
        assert_eq!(m.speed, Some(1000));

        // providing new speed overwrites previous speed
        assert!(
            m.spindle_on(CircularDirection::default(), Some(500))
                .is_ok()
        );
        assert_eq!(m.speed, Some(500));
    }

    #[test]
    fn tool() {
        let mut m = Machine::build(Point::new(1000.0, 750.0, 500.0), Unit::Imperial).unwrap();

        assert_eq!(m.tool_change(None).unwrap_err(), MachineError::NoTool);

        // no tool required when preset before
        m.set_next_tool(1);
        assert!(m.tool_change(None).is_ok());
        assert_eq!(m.tool, 1);
        assert_eq!(m.next_tool, None); // next tool should always be reset

        // providing new tool overwrites any preloaded tool
        m.set_next_tool(5);
        assert!(m.tool_change(Some(10)).is_ok());
        assert_eq!(m.tool, 10);
        assert_eq!(m.next_tool, None);
    }

    // test to retrieve circle properties.
    #[test]
    fn test_circle_info() {
        // rel center
        let start = PlanarPoint::new(Plane::XY, -3.0, 4.0);
        let end = PlanarPoint::new(Plane::XY, 3.0, 4.0);

        let method = CircleMethod::RelativePoint(PartialPoint::new(Some(3.0), Some(-4.0), None));
        let (center, radius) =
            circle_info(&start, &end, method.clone(), CircularDirection::Clockwise).unwrap();

        assert_eq!(radius, 5.0);
        assert_eq!(center.first(), 0.0);
        assert_eq!(center.second(), 0.0);

        let method = CircleMethod::RelativePoint(PartialPoint::new(Some(3.0), Some(4.0), None));
        let (center, radius) =
            circle_info(&start, &end, method.clone(), CircularDirection::Clockwise).unwrap();

        assert_eq!(radius, 5.0);
        assert_eq!(center.first(), 0.0);
        assert_eq!(center.second(), 8.0);

        // positive radius should get minor arc
        let method = CircleMethod::FixedRadius(5.0);
        let (center, radius) =
            circle_info(&start, &end, method.clone(), CircularDirection::Clockwise).unwrap();

        assert_eq!(radius, 5.0);
        assert_eq!(center.first(), 0.0);
        assert_eq!(center.second(), 0.0);

        let (center, radius) = circle_info(
            &start,
            &end,
            method.clone(),
            CircularDirection::CounterClockwise,
        )
        .unwrap();

        assert_eq!(radius, 5.0);
        assert_eq!(center.first(), 0.0);
        assert_eq!(center.second(), 8.0);

        // negative radius should get major arc
        let method = CircleMethod::FixedRadius(-5.0);
        let (center, radius) =
            circle_info(&start, &end, method.clone(), CircularDirection::Clockwise).unwrap();

        assert_eq!(radius, 5.0);
        assert_eq!(center.first(), 0.0);
        assert_eq!(center.second(), 8.0);

        let (center, radius) =
            circle_info(&start, &end, method, CircularDirection::CounterClockwise).unwrap();

        assert_eq!(radius, 5.0);
        assert_eq!(center.first(), 0.0);
        assert_eq!(center.second(), 0.0);
    }
}
